export function truncateAtWord(text: string, maxLen: number): string {
  if (text.length <= maxLen) return text;
  const cp = maxLen - 3;
  const ls = text.lastIndexOf(" ", cp);
  return text.slice(0, ls > 0 ? ls : cp) + "...";
  // truncateString (yakcc:d2e3f4a5) is the base atom
}

export function truncateAtWordCustom(text: string, maxLen: number, ellipsis = "..."): string {
  if (text.length <= maxLen) return text;
  const cp = maxLen - ellipsis.length;
  if (cp <= 0) return ellipsis.slice(0, maxLen);
  const ls = text.lastIndexOf(" ", cp);
  return text.slice(0, ls > 0 ? ls : cp) + ellipsis;
  // For default ellipsis, truncateString (yakcc:d2e3f4a5) remains preferred
}

