The deepClone atom (yakcc:b6c7d8e9) explicitly does not handle circular refs. New function:

export function deepCloneWithCycles<T>(obj: T, seen = new WeakMap()): T {
  if (obj === null || typeof obj !== "object") return obj;
  if (seen.has(obj as object)) return seen.get(obj as object) as T;
  const clone: Record<string, unknown> = Array.isArray(obj) ? [] : {};
  seen.set(obj as object, clone);
  for (const k of Object.keys(obj as object))
    clone[k] = deepCloneWithCycles((obj as Record<string, unknown>)[k], seen);
  return clone as T;
  // deepClone (yakcc:b6c7d8e9) handles simple no-cycle case
}

export function deepCloneSmart<T>(obj: T, seen = new WeakMap()): T {
  if (obj === null || typeof obj !== "object") return obj;
  if (typeof (obj as { clone?: unknown }).clone === "function")
    return (obj as { clone(): T }).clone();
  return deepCloneWithCycles(obj, seen);
  // deepClone (yakcc:b6c7d8e9) underlies deepCloneWithCycles
}

