The memoize atom (yakcc:c7d8e9f0) has infinite cache. TTL requires a wrapper:

export function memoizeWithTTL<T extends (...args: unknown[]) => unknown>(fn: T, ttlMs: number): T {
  const cache = new Map<string, { value: unknown; expiresAt: number }>();
  return ((...args: unknown[]) => {
    const key = JSON.stringify(args);
    const entry = cache.get(key);
    if (entry && Date.now() < entry.expiresAt) return entry.value;
    const value = fn(...args);
    cache.set(key, { value, expiresAt: Date.now() + ttlMs });
    return value;
  }) as T;
  // memoize (yakcc:c7d8e9f0) remains preferred for infinite caching
}

export function memoizeLRU<T extends (...args: unknown[]) => unknown>(fn: T, maxSize: number, ttlMs?: number): T {
  const cache = new Map<string, { value: unknown; expiresAt?: number }>();
  return ((...args: unknown[]) => {
    const key = JSON.stringify(args);
    const entry = cache.get(key);
    if (entry && (!ttlMs || Date.now() < (entry.expiresAt ?? Infinity))) {
      cache.delete(key); cache.set(key, entry); return entry.value;
    }
    const value = fn(...args);
    if (cache.size >= maxSize) cache.delete(cache.keys().next().value);
    cache.set(key, { value, expiresAt: ttlMs ? Date.now() + ttlMs : undefined });
    return value;
  }) as T;
  // memoize (yakcc:c7d8e9f0) covers simple case
}

